Code:
public String alarmClock(int day, boolean vacation) {
    // Determine if it's a weekday
    boolean isWeekday = (day >= 1 && day <= 5);

    // If it's a vacation
    if (vacation) {
        // Weekdays during vacation
        if (isWeekday) {
            return "10:00";
        } else {
            // Weekends during vacation
            return "off";
        }
    } else {
        // Not a vacation
        if (isWeekday) {
            // Weekdays
            return "7:00";
        } else {
            // Weekends
            return "10:00";
        }
    }
}

